+import { createModifier } from '../modifier';
+import type { PredicateData, PredicateModifier } from '../types';
+
+let predicateId = 1_000_000;
+
+/** Create a value-based query filter. Predicate dependencies must be data traits. */
+export function createPredicate<T extends Trait[]>(
+    traits: T,
+    predicate: (data: PredicateData<T>) => boolean
+): PredicateModifier<T> {
+    for (const trait of traits) {
+        if (trait[$internal].type === 'tag') {
+            throw new Error('Koota: Tags cannot be predicate dependencies.');
+        }
+        if (isRelation(trait) || trait[$internal].relation) {
+            throw new Error('Koota: Relations cannot be predicate dependencies.');
+        }
+    }
+
+    return Object.assign(createModifier(`predicate-${predicateId}`, predicateId++, traits), {
+        predicate,
+        isPredicate: true as const,
+    });
+}
+
+/** @inline */
+export function matchesPredicate(
+    world: World,
+    entity: Entity,
+    modifier: PredicateModifier
+): boolean {
+    const ctx = world[$internal];
+    const eid = getEntityId(entity);
+    const data: unknown[] = [];
+
+    for (const trait of modifier.traits) {
+        const instance = ctx.traitInstances[trait.id];
+        if (!instance) return false;
+        const mask = ctx.entityMasks[instance.generationId]?.[eid] || 0;
+        if ((mask & instance.bitflag) !== instance.bitflag) return false;
+        data.push(trait[$internal].get(eid, instance.store));
+    }
+
+    return modifier.predicate(data as PredicateData<Trait[]>);
+}
